<script lang="ts">import { formatCurrency } from '$lib/utils/format'; let { data } = $props();</script>
<div class="mx-auto max-w-5xl px-6 py-10"><div class="no-print mb-6 flex justify-end gap-3"><button class="btn-secondary" data-testid="print-button" onclick={() => window.print()}>Print / Save PDF</button><a class="btn-primary" href={`/app/invoices/${data.invoice.id}`}>Back to editor</a></div><article class="card rounded-[2rem] p-10"><header data-testid="print-invoice-header" class="flex flex-wrap items-start justify-between gap-8 border-b border-slate-100 pb-8"><div><p class="text-sm font-medium uppercase tracking-[0.2em] text-brand-600">Invoice</p><h1 class="mt-4 text-4xl font-semibold text-slate-900">{data.invoice.invoiceNumber}</h1><p class="mt-3 text-sm text-slate-500">Issue date: {data.invoice.issueDate}</p><p class="mt-1 text-sm text-slate-500">Due date: {data.invoice.dueDate}</p></div><div class="max-w-sm text-right text-sm text-slate-600"><h2 class="text-xl font-semibold text-slate-900">{data.profile.companyName}</h2><p class="mt-2 whitespace-pre-line">{data.profile.companyAddress}</p><p class="mt-2">{data.profile.companyEmail}</p><p>{data.profile.companyPhone}</p></div></header><section class="grid gap-8 border-b border-slate-100 py-8 md:grid-cols-2"><div><p class="text-sm uppercase tracking-[0.2em] text-slate-400">Bill to</p><h3 class="mt-3 text-xl font-semibold text-slate-900">{data.invoice.customerName}</h3><p class="mt-2 whitespace-pre-line text-sm text-slate-600">{data.invoice.customerAddress}</p><p class="mt-2 text-sm text-slate-600">{data.invoice.customerEmail}</p></div><div class="md:text-right"><p class="text-sm uppercase tracking-[0.2em] text-slate-400">Status</p><p class="mt-3 text-xl font-semibold text-slate-900">{data.invoice.status}</p></div></section><section class="py-8"><table class="min-w-full text-left text-sm"><thead><tr class="border-b border-slate-100 text-slate-400"><th class="py-4 font-medium">Description</th><th class="py-4 text-right font-medium">Qty</th><th class="py-4 text-right font-medium">Rate</th><th class="py-4 text-right font-medium">Amount</th></tr></thead><tbody>{#each data.invoice.items as item}<tr class="border-b border-slate-50 align-top"><td class="py-4 pr-6"><p class="font-medium text-slate-900">{item.name}</p><p class="mt-2 whitespace-pre-line text-slate-500">{item.description}</p></td><td class="py-4 text-right text-slate-600">{item.quantity}</td><td class="py-4 text-right text-slate-600">{formatCurrency(item.unitPrice, data.invoice.currency)}</td><td class="py-4 text-right font-medium text-slate-900">{formatCurrency(item.lineTotal, data.invoice.currency)}</td></tr>{/each}</tbody></table></section><section class="grid gap-8 border-t border-slate-100 pt-8 md:grid-cols-[1fr_320px]"><div class="space-y-6 text-sm text-slate-600"><div><p class="text-sm uppercase tracking-[0.2em] text-slate-400">Notes</p><p class="mt-3 whitespace-pre-line">{data.invoice.notes || 'Thank you for your business.'}</p></div><div><p class="text-sm uppercase tracking-[0.2em] text-slate-400">Payment instructions</p><p class="mt-3 whitespace-pre-line">{data.invoice.paymentInstructions}</p></div></div><div class="space-y-4 rounded-3xl bg-slate-50 p-6 text-sm"><div class="flex justify-between"><span>Subtotal</span><span>{formatCurrency(data.invoice.subtotal, data.invoice.currency)}</span></div><div class="flex justify-between"><span>Discount</span><span>-{formatCurrency(data.invoice.discountAmount, data.invoice.currency)}</span></div><div class="flex justify-between"><span>Tax</span><span>{formatCurrency(data.invoice.taxAmount, data.invoice.currency)}</span></div><div data-testid="print-total-due" class="flex justify-between border-t border-slate-200 pt-4 text-base font-semibold text-slate-900"><span>Total due</span><span>{formatCurrency(data.invoice.totalAmount, data.invoice.currency)}</span></div></div></section></article></div>
